<div class="page-title-row"><div><p class="text-muted mb-1">Quality management</p><h1>Corrective Action SLA</h1></div><a class="btn btn-outline-primary" href="/portal/corrective-actions">Manage actions</a></div>
<div class="row g-3 mb-4"><div class="col-md-3"><div class="metric-card"><div><span>Open total</span><strong><?=number_format((int)$summary['total']-(int)$summary['completed'])?></strong></div><i class="fa-solid fa-list-check text-primary"></i></div></div><div class="col-md-3"><div class="metric-card"><div><span>Overdue</span><strong><?=number_format((int)$summary['overdue'])?></strong></div><i class="fa-solid fa-triangle-exclamation text-danger"></i></div></div><div class="col-md-3"><div class="metric-card"><div><span>Due in 24 hours</span><strong><?=number_format((int)$summary['due_24h'])?></strong></div><i class="fa-solid fa-clock text-warning"></i></div></div><div class="col-md-3"><div class="metric-card"><div><span>Completed</span><strong><?=number_format((int)$summary['completed'])?></strong></div><i class="fa-solid fa-circle-check text-success"></i></div></div></div>
<section class="portal-card"><h2>Active SLA queue</h2><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Action</th><th>Severity</th><th>Assigned</th><th>Due</th><th>SLA</th></tr></thead><tbody><?php foreach($actions as $a):?><tr><td><strong><?=e($a['title'])?></strong><small><?=e($a['job_number']?:'No job')?></small></td><td><?=e($a['severity'])?></td><td><?=e($a['assigned_name']?:'Unassigned')?></td><td><?=e($a['due_at']?:'No due date')?></td><td><?php if($a['due_at']&&$a['hours_overdue']>0):?><span class="badge text-bg-danger"><?=number_format((int)$a['hours_overdue'])?>h overdue</span><?php elseif($a['due_at']):?><span class="badge text-bg-success">Within SLA</span><?php else:?><span class="badge text-bg-secondary">Unscheduled</span><?php endif?></td></tr><?php endforeach?></tbody></table></div></section>
